/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(AssetTable, Location), FormControlEventType::PageActivated)]
public static void Location_OnPageActivated(FormControl sender, FormControlEventArgs e)
{
    FormRun element = sender.formRun();
    FormDataSource   assetTable_ds =  element.datasource(formDataSourceStr(AssetTable, AssetTable)) as FormDataSource;
    AssetTable assetTable = assetTable_ds.cursor();
    FormReferenceGroupControl FRGC;

    if(assetTable.DataAreaId == 'GFAM')
    {
        FRGC = element.design().controlname("Inventory_WorkerContactName");
        if(FRGC)
        {
            FRGC.label("User Id");
        }
    }
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(AssetTable, AssetTable), FormDataSourceEventType::Activated)]
public static void AssetTable_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun element = sender.formRun();
    FormDataSource   assetTable_ds =  element.datasource(formDataSourceStr(AssetTable, AssetTable)) as FormDataSource;
    AssetTable assetTable = assetTable_ds.cursor();

    FormTabPageControl ftpc = element.design().controlname("ETGFixedAseets");

    if(assetTable.DataAreaId == 'GFAM')
    {          
        if(ftpc)
        {
            ftpc.visible(true);
        }
    }
    else
    {
        if(ftpc)
        {
            ftpc.visible(false);
        }
    }
}

//NS, DLT, 07032025, unit of measure restriction  on fixed asset
/// <summary>
/// unit of measure restriction  on fixed asset
/// </summary>
/// <param name="sender">FormControl sender</param>
/// <param name="e">FormControlEventArgs e</param>
[FormControlEventHandler(formControlStr(AssetTable, Quantity_UnitOfMeasure), FormControlEventType::Lookup)]
public static void Quantity_UnitOfMeasure_OnLookup(FormControl sender, FormControlEventArgs e)
{
    if(ETGACFParameters::find().EnableUATSmallPoints == NoYes::Yes)
    {
        Query query = new Query();
        QueryBuildDataSource queryBuildDataSource;
        QueryBuildRange queryBuildRange;

        SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(UnitOfMeasure), sender);

        sysTableLookup.addLookupField(fieldNum(UnitOfMeasure, Symbol));

        queryBuildDataSource = query.addDataSource(tableNum(UnitOfMeasure));

        SysQuery::findOrCreateRange(queryBuildDataSource, fieldNum(UnitOfMeasure, ETGFixedAssetUnit)).value(queryValue(NoYes::Yes));

        sysTableLookup.parmQuery(query);
        sysTableLookup.performFormLookup();

        FormControlCancelableSuperEventArgs cancelableSuperEventArgs = e as FormControlCancelableSuperEventArgs;
        cancelableSuperEventArgs.CancelSuperCall();
    }

}
//NE, DLT, 07032025, unit of measure restriction  on fixed asset
